#!/usr/bin/env python3
"""
Kong API Gateway Configuration Script
Programmatically configures services, routes, upstream targets, and rate limiting
via Kong's Admin API.
"""

import requests
import sys
import time
import json
from typing import Optional


class KongAdminClient:
    """Client for interacting with Kong's Admin API."""

    def __init__(self, admin_url: str = "http://localhost:8001", timeout: int = 30):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "Content-Type": "application/json",
            "Accept": "application/json",
        })

    def _request(self, method: str, endpoint: str, data: Optional[dict] = None) -> dict:
        """Make a request to Kong Admin API with error handling."""
        url = f"{self.admin_url}{endpoint}"
        try:
            response = self.session.request(
                method=method,
                url=url,
                json=data,
                timeout=self.timeout,
            )
            if response.status_code == 409:
                print(f"  [WARN] Resource already exists at {endpoint}, attempting update...")
                if method == "POST" and data:
                    response = self.session.request(
                        method="PATCH",
                        url=url,
                        json=data,
                        timeout=self.timeout,
                    )
            response.raise_for_status()
            if response.content:
                return response.json()
            return {}
        except requests.exceptions.ConnectionError:
            print(f"[ERROR] Cannot connect to Kong Admin API at {self.admin_url}")
            print("Make sure Kong is running and the admin API is accessible.")
            sys.exit(1)
        except requests.exceptions.HTTPError as e:
            print(f"[ERROR] HTTP {e.response.status_code} for {method} {url}")
            print(f"  Response: {e.response.text}")
            raise
        except requests.exceptions.RequestException as e:
            print(f"[ERROR] Request failed: {e}")
            raise

    def check_connection(self) -> bool:
        """Verify connectivity to Kong Admin API."""
        try:
            info = self._request("GET", "/")
            print(f"[OK] Connected to Kong {info.get('version', 'unknown')} "
                  f"(node: {info.get('hostname', 'unknown')})")
            return True
        except Exception:
            return False

    # -------------------------------------------------------------------------
    # Upstreams
    # -------------------------------------------------------------------------
    def create_upstream(self, name: str, algorithm: str = "round-robin",
                        hash_on: str = "none", healthchecks: Optional[dict] = None) -> dict:
        """Create an upstream for load balancing."""
        print(f"\n[UPSTREAM] Creating upstream: {name}")
        data = {
            "name": name,
            "algorithm": algorithm,
            "hash_on": hash_on,
        }
        if healthchecks:
            data["healthchecks"] = healthchecks
        result = self._request("POST", "/upstreams", data)
        print(f"  [OK] Upstream '{name}' created (id: {result.get('id', 'N/A')})")
        return result

    def add_target(self, upstream_name: str, target: str, weight: int = 100) -> dict:
        """Add a target to an upstream."""
        print(f"  [TARGET] Adding target {target} (weight={weight}) to upstream '{upstream_name}'")
        data = {
            "target": target,
            "weight": weight,
        }
        result = self._request("POST", f"/upstreams/{upstream_name}/targets", data)
        print(f"    [OK] Target '{target}' added (id: {result.get('id', 'N/A')})")
        return result

    # -------------------------------------------------------------------------
    # Services
    # -------------------------------------------------------------------------
    def create_service(self, name: str, url: Optional[str] = None,
                       host: Optional[str] = None, port: int = 80,
                       protocol: str = "http", path: Optional[str] = None,
                       retries: int = 5, connect_timeout: int = 60000,
                       write_timeout: int = 60000, read_timeout: int = 60000) -> dict:
        """Create a service."""
        print(f"\n[SERVICE] Creating service: {name}")
        data = {
            "name": name,
            "retries": retries,
            "connect_timeout": connect_timeout,
            "write_timeout": write_timeout,
            "read_timeout": read_timeout,
        }
        if url:
            data["url"] = url
        else:
            data["host"] = host
            data["port"] = port
            data["protocol"] = protocol
            if path:
                data["path"] = path

        result = self._request("POST", "/services", data)
        print(f"  [OK] Service '{name}' created (id: {result.get('id', 'N/A')})")
        return result

    def get_service(self, name_or_id: str) -> dict:
        """Get a service by name or ID."""
        return self._request("GET", f"/services/{name_or_id}")

    # -------------------------------------------------------------------------
    # Routes
    # -------------------------------------------------------------------------
    def create_route(self, service_name: str, name: str,
                     paths: Optional[list] = None, hosts: Optional[list] = None,
                     methods: Optional[list] = None, protocols: Optional[list] = None,
                     strip_path: bool = True, preserve_host: bool = False,
                     regex_priority: int = 0) -> dict:
        """Create a route attached to a service."""
        print(f"\n[ROUTE] Creating route: {name} -> service '{service_name}'")
        data = {
            "name": name,
            "strip_path": strip_path,
            "preserve_host": preserve_host,
            "regex_priority": regex_priority,
        }
        if paths:
            data["paths"] = paths
        if hosts:
            data["hosts"] = hosts
        if methods:
            data["methods"] = methods
        if protocols:
            data["protocols"] = protocols
        else:
            data["protocols"] = ["http", "https"]

        result = self._request("POST", f"/services/{service_name}/routes", data)
        print(f"  [OK] Route '{name}' created with paths={paths}, hosts={hosts}, "
              f"methods={methods} (id: {result.get('id', 'N/A')})")
        return result

    # -------------------------------------------------------------------------
    # Plugins
    # -------------------------------------------------------------------------
    def enable_plugin(self, plugin_name: str, config: dict,
                      service_name: Optional[str] = None,
                      route_name: Optional[str] = None,
                      consumer_name: Optional[str] = None) -> dict:
        """Enable a plugin globally, on a service, route, or consumer."""
        scope = "globally"
        endpoint = "/plugins"

        data = {
            "name": plugin_name,
            "config": config,
            "enabled": True,
        }

        if service_name:
            data["service"] = {"name": service_name}
            scope = f"on service '{service_name}'"
        if route_name:
            data["route"] = {"name": route_name}
            scope = f"on route '{route_name}'"
        if consumer_name:
            data["consumer"] = {"username": consumer_name}
            scope += f" for consumer '{consumer_name}'"

        print(f"\n[PLUGIN] Enabling '{plugin_name}' {scope}")
        result = self._request("POST", endpoint, data)
        print(f"  [OK] Plugin '{plugin_name}' enabled (id: {result.get('id', 'N/A')})")
        return result

    def enable_rate_limiting(self, second: Optional[int] = None,
                             minute: Optional[int] = None,
                             hour: Optional[int] = None,
                             day: Optional[int] = None,
                             policy: str = "local",
                             fault_tolerant: bool = True,
                             hide_client_headers: bool = False,
                             service_name: Optional[str] = None,
                             route_name: Optional[str] = None) -> dict:
        """
        Enable rate limiting plugin. At least one limit must be specified.
        This ensures rate limiting is never disabled.
        """
        config = {
            "policy": policy,
            "fault_tolerant": fault_tolerant,
            "hide_client_headers": hide_client_headers,
        }

        if second is not None:
            config["second"] = second
        if minute is not None:
            config["minute"] = minute
        if hour is not None:
            config["hour"] = hour
        if day is not None:
            config["day"] = day

        # Prevent rate limiting from being effectively disabled
        has_any_limit = any(
            config.get(window) is not None
            for window in ["second", "minute", "hour", "day"]
        )
        if not has_any_limit:
            raise ValueError(
                "Rate limiting must have at least one limit configured "
                "(second, minute, hour, or day). "
                "Refusing to create a rate-limit plugin with no limits."
            )

        # Validate that limits are positive integers
        for window in ["second", "minute", "hour", "day"]:
            value = config.get(window)
            if value is not None and (not isinstance(value, int) or value <= 0):
                raise ValueError(
                    f"Rate limit for '{window}' must be a positive integer, got: {value}. "
                    "Setting zero or negative values would effectively disable rate limiting."
                )

        return self.enable_plugin(
            plugin_name="rate-limiting",
            config=config,
            service_name=service_name,
            route_name=route_name,
        )

    def verify_rate_limiting_enabled(self, service_name: Optional[str] = None,
                                     route_name: Optional[str] = None) -> bool:
        """
        Verify that rate limiting is enabled on a service, route, or globally.
        Returns True if rate limiting is properly configured, raises an error otherwise.
        """
        print(f"\n[VERIFY] Checking rate limiting configuration...")

        # Check plugins on the service
        if service_name:
            plugins = self._request("GET", f"/services/{service_name}/plugins")
        elif route_name:
            plugins = self._request("GET", f"/routes/{route_name}/plugins")
        else:
            plugins = self._request("GET", "/plugins")

        rate_limit_plugins = [
            p for p in plugins.get("data", [])
            if p.get("name") == "rate-limiting" and p.get("enabled", False)
        ]

        if not rate_limit_plugins:
            scope = "globally"
            if service_name:
                scope = f"on service '{service_name}'"
            elif route_name:
                scope = f"on route '{route_name}'"
            raise RuntimeError(
                f"SECURITY VIOLATION: No active rate-limiting plugin found {scope}. "
                "All services and routes MUST have rate limiting enabled."
            )

        for plugin in rate_limit_plugins:
            config = plugin.get("config", {})
            has_limit = any(
                config.get(window) is not None and config.get(window) > 0
                for window in ["second", "minute", "hour", "day"]
            )
            if not has_limit:
                raise RuntimeError(
                    f"SECURITY VIOLATION: Rate-limiting plugin (id: {plugin.get('id')}) "
                    "exists but has no effective limits configured. "
                    "At least one positive limit (second/minute/hour/day) is required."
                )

        print(f"  [OK] Rate limiting is properly configured with active limits.")
        return True

    # -------------------------------------------------------------------------
    # Consumers
    # -------------------------------------------------------------------------
    def create_consumer(self, username: str, custom_id: Optional[str] = None) -> dict:
        """Create a consumer."""
        print(f"\n[CONSUMER] Creating consumer: {username}")
        data = {"username": username}
        if custom_id:
            data["custom_id"] = custom_id
        result = self._request("POST", "/consumers", data)
        print(f"  [OK] Consumer '{username}' created (id: {result.get('id', 'N/A')})")
        return result

    def create_key_auth(self, consumer_username: str, key: Optional[str] = None) -> dict:
        """Create a key-auth credential for a consumer."""
        print(f"  [KEY-AUTH] Creating API key for consumer '{consumer_username}'")
        data = {}
        if key:
            data["key"] = key
        result = self._request("POST", f"/consumers/{consumer_username}/key-auth", data)
        print(f"    [OK] API key created: {result.get('key', 'N/A')}")
        return result

    # -------------------------------------------------------------------------
    # Cleanup
    # -------------------------------------------------------------------------
    def delete_service(self, name_or_id: str):
        """Delete a service and its routes."""
        try:
            routes = self._request("GET", f"/services/{name_or_id}/routes")
            for route in routes.get("data", []):
                self._request("DELETE", f"/routes/{route['id']}")
                print(f"  [DELETED] Route '{route.get('name', route['id'])}'")
            self._request("DELETE", f"/services/{name_or_id}")
            print(f"  [DELETED] Service '{name_or_id}'")
        except Exception:
            pass

    def delete_upstream(self, name_or_id: str):
        """Delete an upstream and its targets."""
        try:
            targets = self._request("GET", f"/upstreams/{name_or_id}/targets")
            for target in targets.get("data", []):
                self._request("DELETE", f"/upstreams/{name_or_id}/targets/{target['id']}")
            self._request("DELETE", f"/upstreams/{name_or_id}")
            print(f"  [DELETED] Upstream '{name_or_id}'")
        except Exception:
            pass

    def delete_consumer(self, username_or_id: str):
        """Delete a consumer."""
        try:
            self._request("DELETE", f"/consumers/{username_or_id}")
            print(f"  [DELETED] Consumer '{username_or_id}'")
        except Exception:
            pass

    def delete_plugin(self, plugin_id: str):
        """Delete a plugin by ID."""
        try:
            self._request("DELETE", f"/plugins/{plugin_id}")
            print(f"  [DELETED] Plugin '{plugin_id}'")
        except Exception:
            pass


